rawInput.command:
node -e "
const fs=require('fs');
const lines=fs.readFileSync('G:/AI/AIMemory/facts-509424983.md','utf8').split(/\r?\n/).filter(l=>l.startsWith('- [f_'));
const tail=n=>lines.slice(-n);
for(const n of [5,10,15]){
  const t=tail(n);
  const chars=t.join('\n').length;
  const first=t[0].match(/\[(20[0-9-T:.Z]+)\]/)?.[1];
  console.log(n+' 筆: '+chars+' chars, 最舊一筆時間 '+first);
}
"

